import React from "react"
import Select from 'react-select'
//import Calendar from 'react-select-date'
import { Calendar, DateObject } from "react-multi-date-picker"
import { properties } from '../../properties/properties.js'
import Moment from 'moment'



class GetBlock extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0
        };
    }

    componentDidMount() {


        this.setState({screen: 0})

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(properties.backend + `scheduler/block_data`, {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {

            this.setState({results: response})

            this.setState({screen: 1})


          })
          .catch(err => {
            console.log(err);
          });




      }



      tdStyle = (content) => {
        return <td nowrap="true" style={this.tdStyleCSS()} valign="top">{content}</td>
    }

    tdStyleColor = (content, color) => {
        return <td nowrap="true" style={{border: "1px solid black", padding: "6px", backgroundColor: color}} valign="top">{content}</td>
    }


    tdStyleCSS = () => {
        return {border: "1px solid black", padding: "6px"}
    }



          render() {


            var header = "Loading ..."

            var content = []
            var tdArray = []


            if (this.state.screen === 1) {
              header = ""

              this.state.results.map(rec => {
                tdArray.push(<tr><td style={this.tdStyleCSS()} colSpan={9}>{"Block # " + rec.block + " (" + Moment(rec.start_date, "YYYY-MM-DD").format("MM-DD-YYYY") + " - " + Moment(rec.end_date, "YYYY-MM-DD").format("MM-DD-YYYY") + ")"}</td></tr>)

                var td2Array = []

                var td3Array = []
                rec.teams.map(rec2 => {
                    //td2Array.push(this.tdStyle(rec2.team))
                    td2Array.push(<td style={this.tdStyleCSS()}>{rec2.team.replace("M-L Wards Team", "Med")}</td>)

                    var membersArray = []
                    rec2.members.map(rec3 => {
                        var personType = rec3.staff_type
                        var color = "white"
                        if (personType != "MD") {
                            personType = rec3.assign_inter_res.replace("UCW ", "").replace("(a)","").replace("(b)","")
                            if (personType.includes("Intern")) {
                                color = "#d7f5d8"
                            }
                            if (personType.includes("Res")) {
                                color = "#f5e4d7"
                            }
                        } else {
                            personType = "Attending"
                            color = "#d7e0f5"
                        }
                        membersArray.push(<tr>{this.tdStyleColor(personType, color)}{this.tdStyleColor(rec3.name_value, color)}{this.tdStyleColor(Moment(rec3.rotate_start, "YYYY-MM-DD").format("MM-DD-YYYY") + " - " + Moment(rec3.rotate_end, "YYYY-MM-DD").format("MM-DD-YYYY"), color)}</tr>)
                    })

                    td3Array.push(this.tdStyle(<table>{membersArray}</table>))

                })
                tdArray.push(<tr>{td2Array}</tr>)
                tdArray.push(<tr>{td3Array}</tr>)

                tdArray.push(<tr><td style={{height: "50px"}}></td></tr>)



              })

 content.push(<table>{tdArray}</table>)

            console.log(this.state.results)


          }



            return (
<div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>

            );
          }


  };

  export default GetBlock
